# setup_inventario_crud.ps1 - CRUD completo Modulo 5 WMS
# Ejecutar desde: Descargas\START_ERP\START_ERP\

Write-Host "Instalando CRUD Modulo 5 WMS..." -ForegroundColor Cyan

Write-Host "  src/modules/inventory/components/WmsModal.tsx" -ForegroundColor Yellow
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$text = [System.Text.Encoding]::UTF8.GetString($bytes)
$dir = Split-Path "src\modules\inventory\components\WmsModal.tsx" -Parent
if ($dir) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
[System.IO.File]::WriteAllText((Resolve-Path ".").Path + "\src\modules\inventory\components\WmsModal.tsx", $text, [System.Text.Encoding]::UTF8)

